import React, { useState, useRef } from "react";
import "./nominate.css";
import { FiSend, FiCheckCircle, FiUpload, FiTrash2 } from "react-icons/fi";
import { useLanguage } from "../../context/LanguageContext";

import { getContent } from "../../content/content";
import Header from "../header/Header";
import Footer from "../footer/Footer";

// ✅ signature pad
import SignatureCanvas from 'react-signature-canvas';

// ✅ your Google Form submitter (from your code)
import { nominationForm } from "../../forms/nominate";

/* ────────────────────────────────────────────────────────────────────────────
   Official Form Header Component
──────────────────────────────────────────────────────────────────────────── */
const OfficialFormHeader: React.FC<{ data: any }> = ({ data }) => (
  <div className="official-form-header">
    <div className="official-form-header__top">
      <div className="official-form-header__left">
        <p className="org-name">{data.org}</p>
        <p className="center-name">{data.center}</p>
        <div className="divider-small" />
        <p className="form-no">{data.formNo}</p>
      </div>
      <div className="official-form-header__right">
        <p className="country-name">{data.country}</p>
        <p className="motto">{data.motto}</p>
        <div className="divider-medium" />
      </div>
    </div>
  </div>
);

/* ────────────────────────────────────────────────────────────────────────────
   Official Form Footer Component
──────────────────────────────────────────────────────────────────────────── */
const OfficialFormFooter: React.FC<{
  data: any;
  lang: string;
  formData: any;
  handleInputChange: (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => void;
  individualSigPad: React.MutableRefObject<SignatureCanvas | null>;
  organizationSigPad: React.MutableRefObject<SignatureCanvas | null>;
  clearIndividualSig: () => void;
  clearOrganizationSig: () => void;
  isOrganization: boolean;
  handleStampUpload: (e: React.ChangeEvent<HTMLInputElement>) => void;
  processFile: (file: File, base64: string) => void;
  isDragging: boolean;
  setIsDragging: (val: boolean) => void;
}> = ({
  data,
  lang,
  formData,
  handleInputChange,
  individualSigPad,
  organizationSigPad,
  clearIndividualSig,
  clearOrganizationSig,
  isOrganization,
  handleStampUpload,
  processFile,
  isDragging,
  setIsDragging,
}) => {
    const onDragOver = (e: React.DragEvent) => {
      e.preventDefault();
      setIsDragging(true);
    };

    const onDragLeave = (e: React.DragEvent) => {
      e.preventDefault();
      setIsDragging(false);
    };

    const onDrop = (e: React.DragEvent) => {
      e.preventDefault();
      setIsDragging(false);
      const file = e.dataTransfer.files?.[0];
      if (file) {
        if (!file.type.match('image.*')) {
          alert(lang === "en" ? "Only images allowed" : "Chỉ chấp nhận file ảnh");
          return;
        }
        const reader = new FileReader();
        reader.onload = (event) => {
          const base64 = event.target?.result as string;
          processFile(file, base64);
        };
        reader.readAsDataURL(file);
      }
    };

    return (
      <div className="official-form-footer">
        <div className="official-form-footer__location">
          <p>{data.location}</p>
        </div>
        <div className="official-form-footer__signs">
          {/* 1. INDIVIDUAL/NOMINEE BLOCK */}
          <div className="sign-block">
            <p className="sign-title">{data.nomineeSign}</p>
            <p className="sign-note">{data.nomineeSignNote}</p>

            <div className="mini-sig-container">
              <div className="mini-sig-canvas-wrapper">
                <SignatureCanvas
                  ref={individualSigPad}
                  penColor="black"
                  canvasProps={{ className: 'mini-sig-pad' }}
                />
                <button type="button" className="mini-sig-clear" onClick={clearIndividualSig}>
                  <FiTrash2 />
                </button>
              </div>
              <input
                type="text"
                name="signatureName"
                className="mini-sig-name-input"
                required
                value={formData.signatureName || ""}
                onChange={handleInputChange}
                placeholder={lang === "en" ? "Enter Full Name" : "Nhập họ và tên"}
              />
            </div>
            <div className="sign-space" />
          </div>

          {/* 2. ORGANIZATION/UNIT BLOCK */}
          <div className="sign-block">
            <p className="sign-title">{data.unitSign}</p>
            <p className="sign-note">{data.unitSignNote}</p>

            {isOrganization ? (
              <div className="mini-sig-container">
                <div
                  className={`mini-stamp-upload-area ${isDragging ? "dragging" : ""} ${formData.stamp ? "has-file" : ""}`}
                  onDragOver={onDragOver}
                  onDragLeave={onDragLeave}
                  onDrop={onDrop}
                >
                  <input
                    type="file"
                    id="footer-stamp-upload"
                    hidden
                    accept="image/*"
                    onChange={handleStampUpload}
                  />
                  <label htmlFor="footer-stamp-upload" className="mini-stamp-drop-zone">
                    {formData.stamp ? (
                      <div className="stamp-preview">
                        <img src={formData.stamp} alt="Stamp Preview" />
                        <span className="stamp-name">{formData.stampFileName}</span>
                        <div className="stamp-overlay">
                          <FiUpload /> {lang === "en" ? "Change Stamp" : "Thay đổi con dấu"}
                        </div>
                      </div>
                    ) : (
                      <div className="drop-content">
                        <FiUpload className="drop-icon" />
                        <span className="drop-text">
                          {lang === "en" ? "UPLOAD/DROP UNIT STAMP" : "TẢI LÊN/THẢ CON DẤU ĐƠN VỊ"}
                        </span>
                        <span className="drop-subtext">
                          {lang === "en" ? "Click or drag image here" : "Nhấp hoặc kéo ảnh vào đây"}
                        </span>
                      </div>
                    )}
                  </label>
                </div>
              </div>
            ) : (
              <div className="mini-sig-container">
                <div className="mini-stamp-placeholder">
                  <p>{lang === "en" ? "Company stamp only for organizations" : "Con dấu chỉ dành cho đơn vị/tổ chức"}</p>
                </div>
              </div>
            )}
            <div className="sign-space" />
          </div>
        </div>
      </div>
    );
  };

/* ────────────────────────────────────────────────────────────────────────────
   Main Nominate Page
──────────────────────────────────────────────────────────────────────────── */
const Nominate: React.FC = () => {
  const { lang } = useLanguage();
  const content = getContent(lang);
  const section = content?.pages?.nominate?.section || {};
  const form = section.officialForm || {};

  const [formData, setFormData] = useState<any>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isCommitted, setIsCommitted] = useState(false);

  const individualSigPad = useRef<SignatureCanvas | null>(null);
  const organizationSigPad = useRef<SignatureCanvas | null>(null);
  const [isDragging, setIsDragging] = useState(false);

  const isOrganization = formData.entityType && (
    formData.entityType.includes("Governmental") ||
    formData.entityType.includes("Cơ quan/Tổ chức")
  );

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData((prev: any) => ({ ...prev, [name]: value }));
  };

  const handleCheckboxChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setIsCommitted(e.target.checked);
  };

  const clearIndividualSig = () => {
    individualSigPad.current?.clear();
  };

  const clearOrganizationSig = () => {
    organizationSigPad.current?.clear();
  };


  const processFile = (file: File, base64: string) => {
    setFormData((prev: any) => ({
      ...prev,
      stamp: base64,
      stampFileName: file.name
    }));
  };

  const handleStampUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (!file.type.match('image.*')) {
        alert(lang === "en" ? "Only images allowed" : "Chỉ chấp nhận file ảnh");
        return;
      }

      const reader = new FileReader();
      reader.onload = (event) => {
        const base64 = event.target?.result as string;
        processFile(file, base64);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!isCommitted) {
      alert(lang === "en" ? "Please confirm the commitment." : "Vui lòng xác nhận lời cam kết.");
      return;
    }

    // Always use individualSigPad as the primary signature source now
    const activeSigPad = individualSigPad;

    if (activeSigPad.current?.isEmpty()) {
      alert(lang === "en" ? "Please provide your digital signature." : "Vui lòng ký tên của bạn.");
      return;
    }

    if (!formData.signatureName) {
      alert(lang === "en" ? "Please type your full name for signature confirmation." : "Vui lòng nhập họ tên xác nhận chữ ký.");
      return;
    }

    if (isOrganization && !formData.stamp) {
      alert(lang === "en" ? "Please upload your company stamp." : "Vui lòng tải lên con dấu đơn vị.");
      return;
    }

    setIsSubmitting(true);
    try {
      // Always capture from active pad before submit
      const finalSignature = activeSigPad.current?.getTrimmedCanvas().toDataURL("image/png");

      // Mapping fields to your existing Google Form payload if needed, 
      // or using a generic mapper. Since the fields changed, we should adapt the payload.
      const birth = (formData.repDob || "").split("-");
      const dobYear = birth[0] || "";
      const dobMonth = birth[1] || "";
      const dobDay = birth[2] || "";

      const payload = {
        id: Math.floor(1000000000 + Math.random() * 9000000000).toString(),
        website: formData.sourceLink || "KHÔNG CÓ",
        awards: formData.certificates || "KHÔNG CÓ",
        name: formData.unitName || formData.repFullName,
        license: formData.taxCode,
        gender: `Entity: ${formData.entityType || "N/A"}`,
        impact: `Content: ${formData.nominationContent}`,
        organization: formData.unitName,
        type: `Category: ${formData.category || "N/A"}`,
        email: formData.unitEmail,
        role: formData.position,
        experience: `Rep: ${formData.repFullName} | Phone: ${formData.repPhone} | Address: ${formData.repAddress} | CCCD: ${formData.repCccd}`,
        achievements: `Desc: ${formData.detailedDescription} | Media: ${formData.mediaLink} | Time: ${formData.estimatedTime} | Event: ${formData.eventTime} | Location: ${formData.eventLocation}`,
        dobYear,
        dobMonth,
        dobDay,
        nationality: "Vietnam",
        missionVision: formData.nominationContent,
        secondaryEmail: formData.repEmail,
        // Added fields
        signature: finalSignature,
        signatureName: formData.signatureName,
        stamp: formData.stamp || "N/A",
        entityType: formData.entityType || "N/A"
      };

      await nominationForm.submit(payload);
      alert(lang === "en" ? "Submitted successfully! Thank you." : "Đã gửi thành công! Cảm ơn bạn.");
      // Reset form if desired
      setFormData({});
      setIsCommitted(false);
      individualSigPad.current?.clear();
      organizationSigPad.current?.clear();
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } catch (err) {
      console.error("Submission error:", err);
      alert(lang === "en" ? "Submission failed. Please try again." : "Gửi thất bại. Vui lòng thử lại.");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="nominate-page">
      <Header content={content?.pages?.globals?.section?.headerContent} />

      {/* Hero Section */}
      <section className="nominate-hero">
        <img src={section.nominateHero?.bgImage} alt="Hero" className="nominate-hero__bg" />
        <div className="nominate-hero__overlay" />
        <div className="nominate-hero__inner">
          <div className="nominate-hero__content">
            <h1 className="nominate-hero__title">
              <span className="nominate-hero__title-main">{section.nominateHero?.titleMain}</span>
              <span className="nominate-hero__title-sub">{section.nominateHero?.titleSub}</span>
            </h1>
            <p className="nominate-hero__desc">{section.nominateHero?.description}</p>
          </div>
        </div>
      </section>

      {/* Official Form Body */}
      <section className="official-form-section">

        <div className="official-form-container">
          <div className="official-form-paper">
            <OfficialFormHeader data={form.header} />

            <h1 className="official-form-title">{form.title}</h1>

            <div className="official-form-intro">
              {form.intro?.map((p: string, i: number) => (
                <p key={i}>{p}</p>
              ))}
            </div>

            <div className="official-form-contact">
              <p>{form.contactInfo?.phone}</p>
              <p>{form.contactInfo?.email} | {form.contactInfo?.web}</p>
            </div>

            <form onSubmit={handleSubmit} className="official-form">
              {/* PHẦN 1 */}
              <div className="form-part">
                <h2 className="form-part-title">{form.parts?.part1?.title}</h2>

                <div className="form-field-wrapper">
                  <label className="field-label-main">{form.parts?.part1?.field1?.label}</label>
                  <div className="radio-group-vertical">
                    {form.parts?.part1?.field1?.options?.map((opt: string, i: number) => (
                      <label key={i} className="radio-label">
                        <input
                          type="radio"
                          name="entityType"
                          value={opt}
                          required
                          onChange={handleInputChange}
                        />
                        <span className="radio-text">{opt}</span>
                      </label>
                    ))}
                  </div>
                </div>

                <div className="form-field-wrapper">
                  <label className="field-label-main">{form.parts?.part1?.field2?.label}</label>
                  <div className="radio-grid">
                    {form.parts?.part1?.field2?.options?.map((opt: string, i: number) => (
                      <label key={i} className="radio-label">
                        <input
                          type="radio"
                          name="category"
                          value={opt}
                          required
                          onChange={handleInputChange}
                        />
                        <span className="radio-text">{opt}</span>
                      </label>
                    ))}
                  </div>
                </div>
              </div>

              {/* PHẦN 2 */}
              <div className="form-part">
                <h2 className="form-part-title">{form.parts?.part2?.title}</h2>

                {/* PHẦN A */}
                <div className="form-sub-part">
                  <h3 className="form-sub-title">{form.parts?.part2?.partA?.title}</h3>
                  <div className="fields-grid">
                    <div className="input-field full">
                      <label>{form.parts?.part2?.partA?.fields?.fullName}</label>
                      <input
                        type="text"
                        name="unitName"
                        required
                        onChange={handleInputChange}
                        placeholder={form.parts?.part2?.partA?.fields?.fullNamePlaceholder}
                      />
                    </div>
                    <div className="input-field half">
                      <label>{form.parts?.part2?.partA?.fields?.taxCode}</label>
                      <input
                        type="text"
                        name="taxCode"
                        required
                        onChange={handleInputChange}
                        placeholder={form.parts?.part2?.partA?.fields?.taxCodePlaceholder}
                      />
                    </div>
                    <div className="input-field full">
                      <label>{form.parts?.part2?.partA?.fields?.address}</label>
                      <textarea
                        name="unitAddress"
                        required
                        rows={2}
                        onChange={handleInputChange}
                        placeholder={form.parts?.part2?.partA?.fields?.addressPlaceholder}
                      />
                    </div>
                    <div className="input-field half">
                      <label>{form.parts?.part2?.partA?.fields?.legalRep}</label>
                      <input
                        type="text"
                        name="legalRep"
                        required
                        onChange={handleInputChange}
                        placeholder={form.parts?.part2?.partA?.fields?.legalRepPlaceholder}
                      />
                    </div>
                    <div className="input-field half">
                      <label>{form.parts?.part2?.partA?.fields?.position}</label>
                      <input
                        type="text"
                        name="position"
                        required
                        onChange={handleInputChange}
                        placeholder={form.parts?.part2?.partA?.fields?.positionPlaceholder}
                      />
                    </div>
                    <div className="input-field half">
                      <label>{form.parts?.part2?.partA?.fields?.repPhone}</label>
                      <input
                        type="tel"
                        name="repPhone"
                        required
                        onChange={handleInputChange}
                        placeholder={form.parts?.part2?.partA?.fields?.repPhonePlaceholder}
                      />
                    </div>
                    <div className="input-field half">
                      <label>{form.parts?.part2?.partA?.fields?.email}</label>
                      <input
                        type="email"
                        name="unitEmail"
                        required
                        onChange={handleInputChange}
                        placeholder={form.parts?.part2?.partA?.fields?.emailPlaceholder}
                      />
                    </div>
                  </div>
                </div>

                {/* PHẦN B */}
                <div className="form-sub-part">
                  <h3 className="form-sub-title">{form.parts?.part2?.partB?.title}</h3>
                  <div className="fields-grid">
                    <div className="input-field half">
                      <label>{form.parts?.part2?.partB?.fields?.fullName}</label>
                      <input
                        type="text"
                        name="repFullName"
                        required
                        onChange={handleInputChange}
                        placeholder={form.parts?.part2?.partB?.fields?.fullNamePlaceholder}
                      />
                    </div>
                    <div className="input-field half">
                      <label>{form.parts?.part2?.partB?.fields?.phone}</label>
                      <input
                        type="tel"
                        name="repContactPhone"
                        required
                        onChange={handleInputChange}
                        placeholder={form.parts?.part2?.partB?.fields?.phonePlaceholder}
                      />
                    </div>
                    <div className="input-field full">
                      <label>{form.parts?.part2?.partB?.fields?.address}</label>
                      <textarea
                        name="repAddress"
                        required
                        rows={2}
                        onChange={handleInputChange}
                        placeholder={form.parts?.part2?.partB?.fields?.addressPlaceholder}
                      />
                    </div>
                    <div className="input-field half">
                      <label>{form.parts?.part2?.partB?.fields?.email}</label>
                      <input
                        type="email"
                        name="repEmail"
                        required
                        onChange={handleInputChange}
                        placeholder={form.parts?.part2?.partB?.fields?.emailPlaceholder}
                      />
                    </div>
                    <div className="input-field half">
                      <label>{form.parts?.part2?.partB?.fields?.cccd}</label>
                      <input
                        type="text"
                        name="repCccd"
                        required
                        onChange={handleInputChange}
                        placeholder={form.parts?.part2?.partB?.fields?.cccdPlaceholder}
                      />
                    </div>
                    <div className="input-field half">
                      <label>{form.parts?.part2?.partB?.fields?.dob}</label>
                      <input
                        type="date"
                        name="repDob"
                        required
                        onChange={handleInputChange}
                      />
                    </div>
                  </div>
                </div>

                {/* PHẦN C */}
                <div className="form-sub-part">
                  <h3 className="form-sub-title">{form.parts?.part2?.partC?.title}</h3>
                  <div className="fields-grid">
                    <div className="input-field full">
                      <label>{form.parts?.part2?.partC?.fields?.content}</label>
                      <textarea
                        name="nominationContent"
                        required
                        rows={4}
                        onChange={handleInputChange}
                        placeholder={form.parts?.part2?.partC?.fields?.contentPlaceholder}
                      />
                    </div>
                    <div className="input-field full">
                      <label>{form.parts?.part2?.partC?.fields?.description}</label>
                      <textarea
                        name="detailedDescription"
                        required
                        rows={6}
                        onChange={handleInputChange}
                        placeholder={form.parts?.part2?.partC?.fields?.descriptionPlaceholder}
                      />
                    </div>
                    <div className="input-field half">
                      <label>{form.parts?.part2?.partC?.fields?.media}</label>
                      <input
                        type="text"
                        name="mediaLink"
                        required
                        onChange={handleInputChange}
                        placeholder={form.parts?.part2?.partC?.fields?.mediaPlaceholder}
                      />
                    </div>
                    <div className="input-field half">
                      <label>{form.parts?.part2?.partC?.fields?.source}</label>
                      <input
                        type="text"
                        name="sourceLink"
                        required
                        onChange={handleInputChange}
                        placeholder={form.parts?.part2?.partC?.fields?.sourcePlaceholder}
                      />
                    </div>
                    <div className="input-field half">
                      <label>{form.parts?.part2?.partC?.fields?.certificate}</label>
                      <input
                        type="text"
                        name="certificates"
                        required
                        onChange={handleInputChange}
                        placeholder={form.parts?.part2?.partC?.fields?.certificatePlaceholder}
                      />
                    </div>
                    <div className="input-field half">
                      <label>{form.parts?.part2?.partC?.fields?.estimatedTime}</label>
                      <input
                        type="text"
                        name="estimatedTime"
                        required
                        onChange={handleInputChange}
                        placeholder={form.parts?.part2?.partC?.fields?.estimatedTimePlaceholder}
                      />
                    </div>
                    <div className="input-field half">
                      <label>{form.parts?.part2?.partC?.fields?.eventTime}</label>
                      <input
                        type="date"
                        name="eventTime"
                        required
                        onChange={handleInputChange}
                      />
                    </div>
                    <div className="input-field half">
                      <label>{form.parts?.part2?.partC?.fields?.location}</label>
                      <input
                        type="text"
                        name="eventLocation"
                        required
                        onChange={handleInputChange}
                        placeholder={form.parts?.part2?.partC?.fields?.locationPlaceholder}
                      />
                    </div>
                  </div>
                </div>
              </div>

              <OfficialFormFooter
                data={form.footer}
                lang={lang}
                formData={formData}
                handleInputChange={handleInputChange}
                individualSigPad={individualSigPad}
                organizationSigPad={organizationSigPad}
                clearIndividualSig={clearIndividualSig}
                clearOrganizationSig={clearOrganizationSig}
                isOrganization={isOrganization}
                handleStampUpload={handleStampUpload}
                processFile={processFile}
                isDragging={isDragging}
                setIsDragging={setIsDragging}
              />

              <div className="form-actions-official">
                <button type="submit" disabled={isSubmitting} className="submit-btn-official">
                  {isSubmitting ? (
                    lang === "en" ? "Submitting..." : "Đang gửi..."
                  ) : (
                    <>
                      <FiSend /> {lang === "en" ? "Submit Nomination" : "Nộp đơn đề cử"}
                    </>
                  )}
                </button>
              </div>
            </form>
          </div>
        </div>

      </section>

      <Footer content={content?.pages?.globals?.section?.footerContent} />
    </div>
  );
};

export default Nominate;

